UPDATE public.\"FashionFilms\" SET sinopsis = 'Muestra de la colección Vivienne Westwood 2011 Gold, presentada con la canción «Heels» de O.Children.' WHERE film_id = '2ed17cf2-4608-4ca4-83ca-6dfcaea7817d';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Una aristócrata chic de la alta sociedad internacional que pierde todo su dinero y posesiones con la crisis mundial, pero de alguna manera se las arregla para conservar su ropa, accesorios y, lo más importante, su criada, con la que tiene una extraña relación entre dama de compañía, amiga y confidente, quien no la abandonará ni en los peores momentos.' WHERE film_id = '67a035c2-6502-4d27-ba6f-79dca96f24dd';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Una buena charla en una universidad depende de la sólida preparación y la participación vivaz por parte de los estudiantes. Sólo hay una cosa extraña en este auditorio: El profesor exige más que sólo silencio obediente y peticiones de palabra. Pero hay una razón para eso.' WHERE film_id = '8cfb8a23-5d5b-4693-97c0-46eee918e0f6';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Documental que muestra la historia de Bergdorf Goodman, los famosos grandes almacenes de la Quinta Avenida neoyorquina. Incluye entrevistas a grandes diseñadores como Tom Ford, Karl Lagerfeld, Marc Jacobs, Vera Wang, Oscar de la Renta, C. Louboutin, Dolce&Gabbana, Michael Kors y las gemelas Olsen, así como a personajes famosos, clientes de la alta sociedad e iconos de moda.' WHERE film_id = '9e7329ea-7b33-488a-922e-edbe62a4695d';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Un video danza hecho para Louis Vuitton y su colección de zapatos en constante evolución. Formas triangulares, rectangulares y pirámides crean las diferentes composiciones en el espacio. La danza y música dan una sensación retro vintage, pero llena de energía y movimientos, a la vez moderno y atemporal, para comprender y definir mejor a la mujer y el hombre «LV» siempre en movimiento, siempre en sintonía con los tiempos.' WHERE film_id = '9ec7e6ec-5c3b-4a0c-8f49-e1c18bdd9f7f';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Sobre Elio Berhanyer dirigido por Diego Galán. Con testimonios de Agatha Ruiz de la Prada, Antonio Gala, Modesto Lomba o Hannibal Laguna entre otros.' WHERE film_id = 'c1829c42-4b78-4a5c-9262-f0a0257dbb7f';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Un encuentro inesperado con un objeto de su pasado sumerge a un hombre en un estado de ensueño reminiscente. Comienza un viaje en su mente que le lleva a la luz, y le ayuda a recordar algo de vital importancia que una vez había conocido pero que con el tiempo había olvidado: que la verdadera paz viene de dentro.' WHERE film_id = 'fe2996f8-eb29-4627-b261-21244296df02';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Una misteriosa llamada. Un seductor encargo. Una atrevida entrega.' WHERE film_id = 'a8551b78-5fa5-4547-97e1-b3741e26110b';
UPDATE public.\"FashionFilms\" SET sinopsis = 'El video explora la tensión entre los dúos y las ganas de convertirse en su propia persona. Tres dúos de ilustradores, bailarines y trabajadores de la construcción , cada uno tiene su propia historia. Todos trabajan para dar a conocer una imponente huella en la moda monumental. La atmósfera del video te captura con imágenes tanto fuertes como delicadas, que llevan a un sorprendente y orquestado clímax.' WHERE film_id = 'ee39f205-e9af-4287-8df9-98a9d36bfc65';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Documental que recoge el ecléctico estilo y modo de vivir de siete neoyoquirnas de entre 62 y 95 años, basado en el blog del mismo nombre creado por Ari Seth Cohen.' WHERE film_id = 'eb41e63c-d678-4d35-afa1-c59390029ea5';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Elena Anaya interpreta en el fashion Film-editorial una metáfora de la lucha entre el agua y el hombre. Pieza que mezcla el elemento principal de la naturaleza con la sofisticación y el arte de la moda.' WHERE film_id = '2b9af09d-58c6-4e04-868a-5c7dc082eadf';
