UPDATE public.\"FashionFilms\" SET sinopsis = 'Una surrealista visión del viejo dilema sobre qué ponerse, en el que la protagonista se encuentra atrapada en un cambio de vestuario interminable.' WHERE film_id = '0efe0998-cc34-4b90-995f-0e6b91aaac49';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Un espontáneo Fashion Film que cuenta la mágica historia de la alquimia entre el bailarín de ballet Jérémie Bélingard y sus múltiples encuentros con la colección RTW SS 2014 de Hermès.' WHERE film_id = 'a23c450b-e918-4fd0-88bc-7178a74b07dd';
