UPDATE public.\"FashionFilms\" SET sinopsis = 'Un hipnótico retrato de la juventud moderna. Unos eclécticos skaters se deslizan a través de un surrealista paisaje suburbano en el que los arcos dorados de McDonalds se asoman en la distancia. De fondo suena una inquietante versión de “MadWorld”, destacando lo familiar pero a la vez desequilibrado del ambiente.' WHERE film_id = '9544d037-5b9e-46e6-8df4-0251342c0480';
UPDATE public.\"FashionFilms\" SET sinopsis = 'Este Fashion Film explora el tema del narcisismo, mediante un retrato surrealista y obsesivo de la fuerza y belleza femenina capturado con delicadeza.' WHERE film_id = 'cb8849aa-7796-473b-a06b-1a79b09ca751';
