UPDATE public.\"FashionFilms\" SET sinopsis = 'Una narración abstracta sobre las características de un tipo específico de diseño de moda joven alemán y el desarrollo común de los jóvenes talentos alemanes. Una parábola simbolista, dos mujeres jóvenes cuyas funciones y relación no está resuelta. ¿Son amigas, amantes o enemigas? ¿Quién mató a quién? Una representa el rol del joven diseñador y la otra simboliza el entorno de la moda en el que tiene que sobrevivir.' WHERE film_id = 'eccdc238-9b9a-4c23-8630-27f94251e858';
