UPDATE public.\"FashionFilms\" SET sinopsis = 'Surrealista Fashion Film basado en las ideas de los diseñadores graduados en el Royal College of Art. Mientras las ocupantes de un pequeño apartamento se entretienen aburriéndose, echamos un vistazo a sus inusuales actividades. Una pianista de pelo largo pretende estar en una playa, en una sensual recreación de una escena de una película; dos chicas se entretienen dibujando complejos estampados en sus zapatos; una joven luchadora rompe cartones de huevo con la esperanza de crear un bolso de moda; y una extraña pareja se encuentra con una forma poco común de refugiarse de una lluvia inminente.' WHERE film_id = '6db91d8b-e7ea-41d6-9633-2308642fcad1';
